// [V4] CHEQUE SCANNER: FLATTEN — imagePath forwarded through pipeline
const fs = require('fs');
const httpItems = $input.all();
const output = [];

if (!httpItems || httpItems.length === 0) return [];

console.log(`🔍 Flatten V4: ${httpItems.length} items`);

// ── Build lookup: imagePath from Build GPT-OSS Extract (forwarded from Init Job) ──
let ctxItems = [];
try {
  ctxItems = $('Build GPT-OSS Extract Request').all();
  console.log(`📎 Got ${ctxItems.length} context items from Build GPT-OSS`);
} catch(e) {
  console.log('⚠️ Cannot read Build GPT-OSS items, trying Init Job...');
  try { ctxItems = $('Init Job').all(); } catch(e2) {
    try { ctxItems = $items('Init Job'); } catch(e3) {
      console.log('⚠️ Cannot read Init Job items either');
    }
  }
}

// ⚡ LAZY: Read image from disk only now
function getImageData(imgPath, mime) {
  if (!imgPath) return '';
  try {
    if (!fs.existsSync(imgPath)) { console.log('⚠️ File not found:', imgPath); return ''; }
    const imgBuffer = fs.readFileSync(imgPath);
    const b64 = imgBuffer.toString('base64');
    if (b64.length < 100) return '';
    try { fs.unlinkSync(imgPath); } catch(e) {}
    return `data:${mime || 'image/jpeg'};base64,${b64}`;
  } catch(e) {
    console.log('⚠️ Read error:', e.message);
    return '';
  }
}

function pushFallbackRow(ctx, status, msg, imageData) {
  output.push({
    json: {
      jobId: ctx.jobId,
      fileName: ctx.fileName,
      status,
      error: msg,
      instrument_type: 'N/A',
      issuing_bank: 'N/A',
      cheque_date: 'N/A',
      payee_name: 'N/A',
      currency: 'N/A',
      amount: 'N/A',
      cheque_number: 'N/A',
      image_data: imageData || ''
    }
  });
}

for (let i = 0; i < httpItems.length; i++) {
  const httpItem = httpItems[i];
  const body = httpItem.json || {};

  // ── Get context (imagePath, fileName, jobId) from forwarded pipeline ──
  const ctxItem = ctxItems[i] || ctxItems[0];
  const ctxJson = ctxItem ? (ctxItem.json || ctxItem) : {};
  const _ctx = ctxJson._context || ctxJson;
  const imgPath = _ctx.imagePath || ctxJson.imagePath || '';
  const imgMime = _ctx.mimeType || ctxJson.mimeType || 'image/jpeg';
  const currentFileName = _ctx.fileName || ctxJson.fileName || 'unknown';
  const currentJobId = _ctx.jobId || ctxJson.jobId || 'unknown';
  const ctx = { jobId: currentJobId, fileName: currentFileName };

  console.log(`📄 Item ${i}: ${currentFileName} | imagePath: ${imgPath ? '✓' : '✗'}`);

  // ⚡ Lazy read: encode base64 from disk right here
  const fullImageData = getImageData(imgPath, imgMime);

  // Check HTTP errors
  if (body.error || httpItem.error || (body.statusCode && body.statusCode >= 400)) {
    pushFallbackRow(ctx, 'error', 'GPT-OSS request failed', fullImageData);
    continue;
  }

  let parsed = null;
  if (body.cheque_records && Array.isArray(body.cheque_records)) {
    parsed = body;
  } else {
    const msg = body.choices?.[0]?.message;
    let content = '';
    if (typeof msg?.content === 'string') content = msg.content;
    else if (typeof msg?.parsed === 'object') parsed = msg.parsed;

    if (content && !parsed) {
      content = content.trim().replace(/```json\s*/g, '').replace(/```\s*/g, '');
      try {
        parsed = JSON.parse(content);
      } catch (e) {
        const match = content.match(/\{[\s\S]*\}/);
        if (match) try { parsed = JSON.parse(match[0]); } catch(e2) {}
      }
    }
  }

  let dataArray = [];
  if (parsed) {
    if (Array.isArray(parsed)) dataArray = parsed;
    else if (parsed.cheque_records && Array.isArray(parsed.cheque_records)) dataArray = parsed.cheque_records;
    else if (parsed.records && Array.isArray(parsed.records)) dataArray = parsed.records;
    else if (parsed.cheque_record) dataArray = [parsed.cheque_record];
    else if (parsed.instrument_type) dataArray = [parsed];
  }

  if (dataArray.length === 0) {
    pushFallbackRow(ctx, 'empty', 'No cheque record found', fullImageData);
    continue;
  }

  const record = dataArray[0];
  output.push({
    json: {
      jobId: ctx.jobId,
      fileName: ctx.fileName,
      status: 'ok',
      instrument_type: String(record?.instrument_type || 'N/A').trim(),
      issuing_bank: String(record?.issuing_bank || 'N/A').trim(),
      cheque_date: String(record?.cheque_date || 'N/A').trim(),
      payee_name: String(record?.payee_name || 'N/A').trim(),
      currency: String(record?.currency || 'N/A').trim(),
      amount: String(record?.amount || 'N/A').trim(),
      cheque_number: String(record?.cheque_number || 'N/A').trim(),
      image_data: fullImageData
    }
  });
}

return output;

const item = $input.item.json;
const ocrText = String(item.ocrText || '').trim();

if (!ocrText) {
  return {
    json: {
      jobId: item.jobId,
      fileName: item.fileName,
      imagePath: item.imagePath,
      mimeType: item.mimeType,
      requestPayload: null,
      _context: {
        jobId: item.jobId,
        fileName: item.fileName,
        imagePath: item.imagePath,
        mimeType: item.mimeType
      },
      skip: true
    }
  };
}

const systemPrompt = `You are a strict Hong Kong Financial Document Data Extraction Engine.
Parse the OCR text of a bank cheque and return ONLY a valid JSON object. No markdown, no explanations.

### OUTPUT SCHEMA
{
  "cheque_records": [
    {
      "instrument_type": "",
      "issuing_bank": "",
      "cheque_date": "",
      "payee_name": "",
      "currency": "",
      "amount": "",
      "cheque_number": ""
    }
  ]
}

### FIELD EXTRACTION RULES
1. instrument_type: "Cheque", "Cashier's Order", "Bank Draft", or similar.
2. issuing_bank: Full bank name (Chinese + English if available). Fix obvious OCR typos.
3. cheque_date: Logically extract and format the date as YYYY-MM-DD. Handle scattered, merged (e.g., DDMM YYYY), or text-based (e.g., Mar -> 03) components. Default to 20XX for 2-digit years. 
4. payee_name: The recipient on the "PAY" / "付" line. NOT the bank name in the header.
   - OCR often garbles characters. Reconstruct the real entity name using context and common sense.
   - Do not include the written amount (e.g., "Ten Thousand Only") in the payee name.
5. currency: ISO code (e.g., HKD, USD, CNY).
6. amount: Pure numeric string, 2 decimal places, no symbols (e.g., 55237.00).
7. cheque_number: First 6 digits of the MICR line at the bottom. Ignore the rest.

### CRITICAL RULES
- Output raw JSON only.
- Fill every field. Use "N/A" ONLY if the info is completely missing. Do NOT hallucinate.`;
const userPrompt = `OCR TEXT:\n${ocrText}`;

const aiPayload = {
  model: 'gpt-oss:120b',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ],
  temperature: 0.0,
};

return {
  json: {
    jobId: item.jobId,
    fileName: item.fileName,
    imagePath: item.imagePath,
    mimeType: item.mimeType,
    requestPayload: aiPayload,
    _context: {
      jobId: item.jobId,
      fileName: item.fileName,
      imagePath: item.imagePath,
      mimeType: item.mimeType
    }
  }
};

// [V6] Extract OCR Text — FAST: chỉ lấy export_text
const initItems = $('Init Job').all();
const currentIndex = $itemIndex;

const originalItem = initItems[currentIndex] || initItems[0];
const jobId = originalItem ? originalItem.json.jobId : 'unknown';
const fileName = originalItem ? originalItem.json.fileName : 'unknown';
const imagePath = originalItem ? originalItem.json.imagePath : '';
const mimeType = originalItem ? originalItem.json.mimeType : 'image/jpeg';

const src = $input.item.json;

// ⚡ Chỉ lấy export_text — bỏ hết items[], polygon, score
let ocrText = '';

if (src.results && Array.isArray(src.results) && src.results[0]) {
  ocrText = String(src.results[0].export_text || '').trim();
} else if (typeof src.export_text === 'string') {
  ocrText = src.export_text.trim();
} else if (src.choices?.[0]?.message?.content) {
  ocrText = src.choices[0].message.content.trim();
}

// Handle blank
if (!ocrText || /^blank[_\s-]*page$/i.test(ocrText)) {
  return {
    json: {
      jobId, fileName, imagePath, mimeType,
      ocrText: '',
      isBlank: true
    },
  };
}

// Clean tokens
ocrText = ocrText
  .replace(/\r\n/g, '\n')
  .replace(/\u00A0/g, ' ')
  .trim();

// Dedup lines
const rawLines = ocrText.split('\n');
const cleaned = [];
const seen = new Set();

for (const rawLine of rawLines) {
  const line = rawLine.trim();
  if (!line) {
    if (cleaned.length && cleaned[cleaned.length - 1] !== '') cleaned.push('');
    continue;
  }
  const key = line.toLowerCase().replace(/\s+/g, ' ');
  if (seen.has(key)) continue;
  seen.add(key);
  cleaned.push(line);
}

let finalText = cleaned.join('\n').trim();
const HARD_LIMIT = 6000;
if (finalText.length > HARD_LIMIT) {
  finalText = finalText.slice(0, HARD_LIMIT);
}

console.log(`📄 OCR for ${fileName}: ${finalText.length} chars`);

return {
  json: {
    jobId, fileName, imagePath, mimeType,
    ocrText: finalText,
    isBlank: false
  },
};

// [V3] Build PaddleOCR-VL Request
const fs = require('fs');
const item = $input.item.json;

const imagePath = item.imagePath;
if (!imagePath || !fs.existsSync(imagePath)) {
  console.error('❌ File not found:', item.fileName);
  return [];
}

const imgBuffer = fs.readFileSync(imagePath);
const b64 = imgBuffer.toString('base64');

if (b64.length < 100) {
  console.error('❌ Tiny file, skipping:', item.fileName);
  try { fs.unlinkSync(imagePath); } catch(e) {}
  return [];
}

let rawMime = String(item.mimeType || 'image/jpeg').toLowerCase();
if (rawMime === 'image/jpg') rawMime = 'image/jpeg';
if (!rawMime.startsWith('image/')) rawMime = 'image/jpeg';

return {
  json: {
    fileName: item.fileName,
    jobId: item.jobId,
    imagePath: item.imagePath,
    mimeType: item.mimeType,
    _context: { fileName: item.fileName }
  },
  binary: {
    file: {
      data: b64,
      mimeType: rawMime,
      fileName: item.fileName || 'image.jpg'
    }
  }
};

// ======================================================
// 🔧 INIT JOB V4: FILE-BASED + IMAGEMAGICK PREPROCESSING
// ======================================================
const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const MAX_PAGES = 200;
const DPI = 450;
const JPEG_QUALITY = 130;
const CONVERT_TIMEOUT = 300000;
const JOB_DIR = '/tmp/n8n_cheque_jobs';
const ENHANCE_TIMEOUT = 60000;

// ── 🖼️ ImageMagick Enhancement Function ──
let hasImageMagick = false;
try {
  execSync('convert --version', { encoding: 'utf8', timeout: 5000, stdio: 'pipe' });
  hasImageMagick = true;
  console.log('🖼️ ImageMagick detected — will enhance images');
} catch(e) {
  console.log('⚠️ ImageMagick not found — skipping enhancement');
}

function enhanceImage(inputPath) {
  if (!hasImageMagick) return inputPath;
  const dir = path.dirname(inputPath);
  const ext = path.extname(inputPath);
  const base = path.basename(inputPath, ext);
  const enhancedPath = path.join(dir, `${base}_enhanced.jpg`);
  try {
    execSync(
      `convert "${inputPath}" ` +
      `-resize '3000x3000>' ` +
      `-colorspace Gray>' ` +
      `-deskew 40% ` +
      `-normalize ` +
      `-sharpen 0x1 ` +
      `-density 300 ` +
      `-quality 130 ` +
      `"${enhancedPath}"`,
      { timeout: ENHANCE_TIMEOUT, stdio: 'pipe' }
    );
    const stats = fs.statSync(enhancedPath);
    if (stats.size > 1024) {
      console.log(`✨ Enhanced: ${path.basename(inputPath)} → ${(stats.size/1024).toFixed(0)}KB`);
      try { fs.unlinkSync(inputPath); } catch(e) {}
      return enhancedPath;
    } else {
      try { fs.unlinkSync(enhancedPath); } catch(e) {}
      return inputPath;
    }
  } catch(e) {
    console.log(`⚠️ Enhance failed for ${path.basename(inputPath)}: ${e.message}`);
    try { fs.unlinkSync(enhancedPath); } catch(e2) {}
    return inputPath;
  }
}

const binaryData = $input.item.binary;
if (!binaryData) throw new Error('No binary data found.');

if (!fs.existsSync(JOB_DIR)) fs.mkdirSync(JOB_DIR, { recursive: true });

const outputItems = [];
const keys = Object.keys(binaryData);
console.log(`🚀 [CHEQUE SCANNER V4 — PaddleOCR-VL + GPT-OSS] Processing ${keys.length} uploads...`);

let converter = 'pdftoppm';
try {
  execSync('gs --version', { encoding: 'utf8', timeout: 5000, stdio: 'pipe' });
  converter = 'gs';
  console.log('⚡ Using Ghostscript');
} catch(e) {
  console.log('📦 Using pdftoppm');
}

for (const key of keys) {
  const fileInfo = binaryData[key];
  if (!fileInfo) continue;

  let fileBuffer;
  try {
    fileBuffer = await this.helpers.getBinaryDataBuffer(0, key);
  } catch (error) {
    console.error(`❌ Error reading ${key}:`, error);
    continue;
  }

  const originalFileName = fileInfo.fileName || `file_${key}`;
  const mimeType = (fileInfo.mimeType || '').toLowerCase();

  if (mimeType === 'application/pdf' || originalFileName.toLowerCase().endsWith('.pdf')) {
    const uniqueId = Math.random().toString(36).slice(2);
    const tempDir = `/tmp/n8n_cheque_v2_${uniqueId}`;
    const tempPdfPath = `${tempDir}/input.pdf`;

    try {
      fs.mkdirSync(tempDir, { recursive: true });
      fs.writeFileSync(tempPdfPath, fileBuffer);
      fileBuffer = null;

      let totalPages = 0;
      try {
        const result = execSync(`pdfinfo "${tempPdfPath}" | grep "Pages:" | awk '{print $2}'`, {
          encoding: 'utf8', timeout: 15000
        }).trim();
        totalPages = parseInt(result) || 0;
      } catch (e) {
        totalPages = 50;
      }

      const pagesToProcess = Math.min(totalPages, MAX_PAGES);
      console.log(`📑 ${originalFileName}: ${pagesToProcess}p @ ${DPI}dpi`);

      const outputDir = `${tempDir}/pages`;
      fs.mkdirSync(outputDir, { recursive: true });

      if (converter === 'gs') {
        execSync(`gs -dBATCH -dNOPAUSE -dQUIET -sDEVICE=jpeg -dJPEGQ=${JPEG_QUALITY} -r${DPI} -dFirstPage=1 -dLastPage=${pagesToProcess} -sOutputFile="${outputDir}/page-%04d.jpg" "${tempPdfPath}"`, {
          timeout: CONVERT_TIMEOUT
        });
      } else {
        execSync(`pdftoppm -jpeg -jpegopt quality=${JPEG_QUALITY} -r ${DPI} -f 1 -l ${pagesToProcess} "${tempPdfPath}" "${outputDir}/page"`, {
          timeout: CONVERT_TIMEOUT
        });
      }

      try { fs.unlinkSync(tempPdfPath); } catch(e) {}

      const files = fs.readdirSync(outputDir)
        .filter(f => f.endsWith('.jpg'))
        .sort((a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' }));

      for (let idx = 0; idx < files.length; idx++) {
        let imgPath = path.join(outputDir, files[idx]);
        const stats = fs.statSync(imgPath);
        if (stats.size < 2048) {
          try { fs.unlinkSync(imgPath); } catch(e) {}
          continue;
        }
        imgPath = enhanceImage(imgPath);
        outputItems.push({
          json: {
            imagePath: imgPath,
            mimeType: 'image/jpeg',
            fileName: `${originalFileName}_p${idx + 1}.jpg`,
            originalFileName: originalFileName,
            isPdfPage: true,
            pageIndex: idx + 1,
            totalPages: files.length,
            conversionFailed: false
          }
        });
      }
      console.log(`✅ ${originalFileName}: ${outputItems.length} items`);
    } catch (err) {
      console.error(`❌ PDF Error: ${err.message}`);
      try { execSync(`rm -rf "${tempDir}"`); } catch (e) {}
    }
  } else {
    const uniqueId = Math.random().toString(36).slice(2);
    const ext = path.extname(originalFileName).toLowerCase() || '.jpg';
    const tempPath = `/tmp/n8n_cheque_v2_img_${uniqueId}${ext}`;
    fs.writeFileSync(tempPath, fileBuffer);
    fileBuffer = null;
    const finalPath = enhanceImage(tempPath);
    outputItems.push({
      json: {
        imagePath: finalPath,
        mimeType: 'image/jpeg',
        fileName: originalFileName,
        originalFileName: originalFileName,
        isPdfPage: false,
        conversionFailed: false
      }
    });
  }
}

if (outputItems.length === 0) throw new Error('No valid files processed.');

const batchJobId = `chq-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
const totalFiles = outputItems.length;

const jobFile = path.join(JOB_DIR, `${batchJobId}.json`);
fs.writeFileSync(jobFile, JSON.stringify({
  status: 'processing',
  expected: totalFiles,
  done: 0,
  createdAt: new Date().toISOString()
}));
console.log(`📝 Job file created: ${jobFile}`);

outputItems.forEach(item => {
  item.json.jobId = batchJobId;
  item.json.expected = totalFiles;
});

console.log(`🚀 Job: ${batchJobId} | ${totalFiles} items`);
return outputItems;

// [V2] GET STATUS — FILE-BASED (instant visibility)
const fs = require('fs');
const path = require('path');
const input = $input.item.json;
const JOB_DIR = '/tmp/n8n_cheque_jobs';

const jobId = (input.query && input.query.jobId) || (input.body && input.body.jobId) || input.jobId;

if (!jobId) {
  return [{
    json: {
      success: true,
      status: 'alive',
      ping: true,
      timestamp: new Date().toISOString()
    }
  }];
}

const jobFile = path.join(JOB_DIR, `${jobId}.json`);

if (!fs.existsSync(jobFile)) {
  return [{
    json: {
      success: true,
      status: 'pending',
      jobId,
      message: 'Job not found or not started yet'
    }
  }];
}

try {
  const raw = fs.readFileSync(jobFile, 'utf8');
  const entry = JSON.parse(raw);

  if (entry.status === 'completed' || entry.status === 'completed-with-errors') {
    const response = {
      success: true,
      status: entry.status,
      jobId,
      result: entry.result || [],
      completedAt: entry.completedAt
    };
    try { fs.unlinkSync(jobFile); } catch(e) {}
    return [{ json: response }];
  }

  return [{
    json: {
      success: true,
      status: entry.status || 'processing',
      jobId,
      progress: entry.done ? `${entry.done}/${entry.expected || '?'}` : undefined,
      createdAt: entry.createdAt
    }
  }];
} catch(e) {
  return [{
    json: {
      success: true,
      status: 'processing',
      jobId,
      message: 'Reading job status...'
    }
  }];
}

const item = $input.item.json;
const jobId = item.jobId;
const expected = item.expected || 1;

return [{
  json: {
    success: true,
    jobId: jobId,
    expected: expected,
    message: `Processing`,
    timestamp: new Date().toISOString()
  }
}];

// [V4] Save Result — FILE-BASED + Cleanup
const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');
const items = $input.all();
const JOB_DIR = '/tmp/n8n_cheque_jobs';

let jobId = null;
if (items.length > 0 && items[0].json.jobId) {
  jobId = items[0].json.jobId;
} else {
  try { jobId = $('Init Job').first().json.jobId; } catch(e) {}
}

if (jobId) {
  const jobFile = path.join(JOB_DIR, `${jobId}.json`);
  const result = items.map(i => ({ ...i.json }));

  fs.writeFileSync(jobFile, JSON.stringify({
    status: 'completed',
    result: result,
    done: items.length,
    expected: items.length,
    completedAt: new Date().toISOString()
  }));
  console.log(`✅ Job ${jobId} saved to file: ${items.length} rows`);
} else {
  console.log('⚠️ No jobId found');
}

// 🧹 Cleanup temp image files
try {
  execSync('rm -rf /tmp/n8n_cheque_v2_*', { timeout: 10000 });
  console.log('🧹 Temp files cleaned');
} catch(e) {}

return items;
